using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent;

public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient = new();

    [Description("Searches the web for a given query and returns a list of results with titles, URLs, and snippets. Use this to find information about a topic.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var response = await _httpClient.GetFromJsonAsync<JsonElement>(url);

            var results = new List<object>();

            // Extract from Abstract
            if (response.TryGetProperty("Abstract", out var abs) &&
                abs.GetString() is { Length: > 0 } abstractText)
            {
                var source = response.TryGetProperty("AbstractURL", out var aUrl)
                    ? aUrl.GetString() ?? ""
                    : "";

                results.Add(new
                {
                    Title = response.TryGetProperty("Heading", out var h) ? h.GetString() : "Summary",
                    Url = source,
                    Snippet = abstractText
                });
            }

            // Extract from RelatedTopics
            if (response.TryGetProperty("RelatedTopics", out var topics) &&
                topics.ValueKind == JsonValueKind.Array)
            {
                foreach (var topic in topics.EnumerateArray())
                {
                    if (results.Count >= maxResults) break;

                    if (topic.TryGetProperty("Text", out var text) &&
                        text.GetString() is { Length: > 0 } snippet)
                    {
                        results.Add(new
                        {
                            Title = topic.TryGetProperty("FirstURL", out var fUrl)
                                ? ExtractTitle(fUrl.GetString() ?? "") : "Related",
                            Url = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : "",
                            Snippet = snippet
                        });
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No results found for '{query}'. Try rephrasing or using different keywords.";
            }

            return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try again with a different query.";
        }
    }

    private static string ExtractTitle(string url)
    {
        var parts = url.TrimEnd('/').Split('/');
        return parts.Length > 0
            ? Uri.UnescapeDataString(parts[^1]).Replace('_', ' ')
            : "Related";
    }
}

using System.ComponentModel;
using System.Text;

namespace ResearchAgent;

public sealed class NoteTakingTool
{
    private readonly List<(string Topic, string Content)> _notes = [];

    [Description("Saves a research note with a topic label and content. Use this to record key findings, facts, and insights discovered during research.")]
    public string SaveNote(
        [Description("A short topic label for the note (e.g., 'History', 'Key People')")] string topic,
        [Description("The content of the note — facts, quotes, or insights to remember")] string content)
    {
        _notes.Add((topic, content));
        return $"Note saved under '{topic}'. Total notes: {_notes.Count}.";
    }

    [Description("Retrieves all saved research notes. Use this before writing a summary to review what you've learned.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note {i + 1}: {_notes[i].Topic} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

