using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// Register tools
var searchTool = new WebSearchTool();
var noteTool = new NoteTakingTool();

var tools = new AIFunctionFactory[]
    {
        AIFunctionFactory.Create(searchTool.SearchWeb),
        AIFunctionFactory.Create(noteTool.SaveNote),
        AIFunctionFactory.Create(noteTool.GetAllNotes),
    }
    .Cast<AIFunction>()
    .ToList();

// Register chat client via DI with MEAI abstraction
builder.Services.AddChatClient(b => b
    .UseFunctionInvocation()
    .UseOpenAIChatClient(modelId, new OpenAI.OpenAIClient(apiKey)));

var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();

// Build the agent using Microsoft Agent Framework
var agent = new ChatClientAgent(chatClient, "ResearchAgent")
{
    Instructions = """
        You are a research agent. Your job is to research a topic thoroughly by:
        1. Searching the web for information using the SearchWeb tool (make multiple searches with different queries to get broad coverage).
        2. Saving important findings as notes using the SaveNote tool (organize by subtopic).
        3. After gathering enough information, retrieve all notes with GetAllNotes and write a comprehensive summary.

        Always search at least 2-3 different queries per topic to get diverse perspectives.
        Save notes as you go — don't wait until the end.
        End with a well-structured summary that synthesizes your findings.
        """,
};

// Get the research topic
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");
Console.WriteLine(new string('=', 60));

// Run the agent
var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

var chatOptions = new ChatOptions
{
    Temperature = 0f,
    Tools = [.. tools],
};

await foreach (var message in agent.InvokeStreamingAsync(
    history,
    options,
    chatOptions,
    cancellationToken: CancellationToken.None))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine();
Console.WriteLine(new string('=', 60));
Console.WriteLine("Research complete.");

