using Microsoft.Agents.AI;
using Microsoft.Agents.AI.ChatCompletion;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// Register tools
var searchTool = new WebSearchTool();
var noteTool = new NoteTakingTool();

var tools = new AIFunctionFactory[]
    {
        AIFunctionFactory.Create(searchTool.SearchWeb),
        AIFunctionFactory.Create(noteTool.SaveNote),
        AIFunctionFactory.Create(noteTool.GetAllNotes),
    }
    .Cast<AIFunction>()
    .ToList();

// Register chat client via DI with MEAI abstraction
builder.Services.AddChatClient(b => b
    .UseFunctionInvocation()
    .UseOpenAIChatClient(modelId, new OpenAI.OpenAIClient(apiKey)));

var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();

// Build the agent using Microsoft Agent Framework
var agent = new ChatClientAgent(chatClient, "ResearchAgent")
{
    Instructions = """
        You are a research agent. Your job is to research a topic thoroughly by:
        1. Searching the web for information using the SearchWeb tool (make multiple searches with different queries to get broad coverage).
        2. Saving important findings as notes using the SaveNote tool (organize by subtopic).
        3. After gathering enough information, retrieve all notes with GetAllNotes and write a comprehensive summary.

